// Script de registro de pulsaciones Trisco o Michael Clavier
// Este script registra las pulsaciones de teclado en tiempo real

// Variables para almacenar el registro
let keystrokes = [];

// Función para registrar una pulsación
function logKeystroke(key) {
    const timestamp = new Date().toISOString();
    keystrokes.push({
        key: key,
        timestamp: timestamp
    });
    console.log(`Pulsación registrada: ${key} en ${timestamp}`);
}

// Función para iniciar el registro
function startRecording() {
    console.log("Iniciando registro de pulsaciones...");
    document.addEventListener('keydown', function(event) {
        logKeystroke(event.key);
    });
}

// Función para detener el registro
function stopRecording() {
    console.log("Deteniendo registro de pulsaciones...");
    document.removeEventListener('keydown', function(event) {
        logKeystroke(event.key);
    });
}

// Ejemplo de uso
// startRecording(); // Inicia el registro
// stopRecording();  // Detiene el registro
